import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { API_BASE_URL } from '../api';

function ViewMyCard() {
    const { id } = useParams();
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchUserData = async () => {
            try {
                setLoading(true);
                const response = await axios.get(`${API_BASE_URL}/users/${id}`);
                setUser(response.data);
            } catch (error) {
                console.error('Error fetching user data:', error);
                setError('Kart bilgileri bulunamadı.');
            } finally {
                setLoading(false);
            }
        };

        if (id) {
            fetchUserData();
        }
    }, [id]);

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner"></div>
                <p>Kart bilgileri yükleniyor...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="error-container">
                <div className="error-message">
                    <h2>⚠️ Hata</h2>
                    <p>{error}</p>
                    <button onClick={() => window.location.href = '/'}>
                        Ana Sayfaya Dön
                    </button>
                </div>
            </div>
        );
    }

    if (!user) {
        return (
            <div className="error-container">
                <div className="error-message">
                    <h2>🔍 Kart Bulunamadı</h2>
                    <p>ID: {id} olan kart bulunamadı.</p>
                    <button onClick={() => window.location.href = '/'}>
                        Ana Sayfaya Dön
                    </button>
                </div>
            </div>
        );
    }

    const renderSocialLinks = () => {
        if (!user.socialLinks || user.socialLinks.length === 0) {
            return null;
        }

        return (
            <div className="social-links-section">
                <h3>🌐 Sosyal Medya Bağlantıları</h3>
                <div className="social-links-grid">
                    {user.socialLinks.map((link, index) => (
                        <a 
                            key={index}
                            href={link.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="social-link"
                        >
                            <span className="social-platform">{link.platform}</span>
                            <span className="social-url">{link.url}</span>
                        </a>
                    ))}
                </div>
            </div>
        );
    };

    return (
        <div className="view-my-card">
            <div className="card-container">
                <div className="card-header">
                    <h1>📇 Dijital Kartvizit</h1>
                    <p className="card-id">Kart ID: {id}</p>
                </div>

                <div className="card-content">
                    {/* Profile Photo */}
                    {user.profilePicture && (
                        <div className="profile-photo-section">
                            <img 
                                src={`data:image/jpeg;base64,${user.profilePicture}`}
                                alt="Profil Fotoğrafı"
                                className="profile-photo"
                            />
                        </div>
                    )}

                    {/* Personal Information */}
                    <div className="personal-info-section">
                        <h2>👤 Kişisel Bilgiler</h2>
                        <div className="info-grid">
                            <div className="info-item">
                                <strong>Ad Soyad:</strong>
                                <span>{user.fullName}</span>
                            </div>
                            {user.email && (
                                <div className="info-item">
                                    <strong>📧 Email:</strong>
                                    <span>
                                        <a href={`mailto:${user.email}`}>{user.email}</a>
                                    </span>
                                </div>
                            )}
                            {user.phone && (
                                <div className="info-item">
                                    <strong>📞 Telefon:</strong>
                                    <span>
                                        <a href={`tel:${user.phone}`}>{user.phone}</a>
                                    </span>
                                </div>
                            )}
                            {user.company && (
                                <div className="info-item">
                                    <strong>🏢 Şirket:</strong>
                                    <span>{user.company}</span>
                                </div>
                            )}
                            {user.jobTitle && (
                                <div className="info-item">
                                    <strong>💼 Ünvan:</strong>
                                    <span>{user.jobTitle}</span>
                                </div>
                            )}
                            {user.website && (
                                <div className="info-item">
                                    <strong>🌐 Website:</strong>
                                    <span>
                                        <a href={user.website} target="_blank" rel="noopener noreferrer">
                                            {user.website}
                                        </a>
                                    </span>
                                </div>
                            )}
                            {user.address && (
                                <div className="info-item">
                                    <strong>📍 Adres:</strong>
                                    <span>{user.address}</span>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Social Links */}
                    {renderSocialLinks()}

                    {/* Action Buttons */}
                    <div className="action-buttons">
                        <button 
                            className="contact-button"
                            onClick={() => {
                                if (user.phone) {
                                    window.location.href = `tel:${user.phone}`;
                                } else if (user.email) {
                                    window.location.href = `mailto:${user.email}`;
                                }
                            }}
                        >
                            📞 İletişime Geç
                        </button>
                        
                        {user.email && (
                            <button 
                                className="email-button"
                                onClick={() => window.location.href = `mailto:${user.email}`}
                            >
                                📧 Email Gönder
                            </button>
                        )}

                        <button 
                            className="save-contact-button"
                            onClick={() => {
                                // VCard format
                                const vcard = `BEGIN:VCARD
VERSION:3.0
FN:${user.fullName}
${user.email ? `EMAIL:${user.email}` : ''}
${user.phone ? `TEL:${user.phone}` : ''}
${user.company ? `ORG:${user.company}` : ''}
${user.jobTitle ? `TITLE:${user.jobTitle}` : ''}
${user.website ? `URL:${user.website}` : ''}
${user.address ? `ADR:;;${user.address};;;` : ''}
END:VCARD`;
                                
                                const blob = new Blob([vcard], { type: 'text/vcard' });
                                const url = window.URL.createObjectURL(blob);
                                const a = document.createElement('a');
                                a.href = url;
                                a.download = `${user.fullName}.vcf`;
                                a.click();
                                window.URL.revokeObjectURL(url);
                            }}
                        >
                            💾 Kişilere Kaydet
                        </button>
                    </div>
                </div>

                <div className="card-footer">
                    <p>DynamicNFC ile oluşturuldu</p>
                    <a href="/" className="home-link">🏠 Ana Sayfa</a>
                </div>
            </div>
        </div>
    );
}

export default ViewMyCard;
